  const fullRange = generateRange(min, max);

  // Wildcard
  if (field === '*') return fullRange;

  // Step with wildcard: */N
  const stepWildcard = /^\*\/(\d+)$/.exec(field);
  if (stepWildcard) {
    const step = parseInt(stepWildcard[1], 10);
    if (step <= 0) throw new RangeError(`Step must be > 0, got: ${step}`);
    return clamp(fullRange.filter(v => (v - min) % step === 0), min, max);
  }

  // Comma-separated list — recurse on each part
  if (field.includes(',')) {
    const values = field
      .split(',')
      .flatMap(part => parseField(part.trim(), min, max));
    return clamp(values, min, max);
  }

  // Range with optional step: N-M or N-M/S
  const rangeStep = /^(\d+)-(\d+)(?:\/(\d+))?$/.exec(field);
  if (rangeStep) {
    const start = parseInt(rangeStep[1], 10);
    const end   = parseInt(rangeStep[2], 10);
    const step  = rangeStep[3] ? parseInt(rangeStep[3], 10) : 1;
    if (step <= 0) throw new RangeError(`Step must be > 0, got: ${step}`);
    const rangeValues = generateRange(start, end).filter((_, i) => i % step === 0);
    return clamp(rangeValues, min, max);
  }

  // Single number
  const single = /^(\d+)$/.exec(field);
  if (single) {
    const v = parseInt(single[1], 10);
    if (v < min || v > max) throw new RangeError(`Value ${v} out of range [${min}, ${max}]`);
    return [v];
  }

  throw new SyntaxError(`Unrecognized cron field expression: "${field}"`);
}

