  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = parts;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dayOfWeekExpr, "dayOfWeek"),
  };
}

type CronField = {
  min: number;
  max: number;
};

const FIELD_RANGES: Record<string, CronField> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 6 },
};

const FIELD_NAMES = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;
type FieldName = (typeof FIELD_NAMES)[number];

export type ParsedCron = Record<FieldName, number[]>;

function clamp(value: number, min: number, max: number): number {
  return Math.min(Math.max(value, min), max);
}

function rangeArray(from: number, to: number): number[] {
  const result: number[] = [];
  for (let i = from; i <= to; i++) result.push(i);
  return result;
}

function parseSegment(segment: string, { min, max }: CronField): number[] {
  // Wildcard
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Step: */n or start/n
  if (segment.includes("/")) {
    const [base, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value in segment: "${segment}"`);
    }
    let from = min;
    let to = max;
    if (base !== "*") {
      if (base.includes("-")) {
        const [rangeStart, rangeEnd] = base.split("-").map(Number);
        from = clamp(rangeStart, min, max);
        to = clamp(rangeEnd, min, max);
      } else {
        from = clamp(parseInt(base, 10), min, max);
      }
    }
    const result: number[] = [];
    for (let i = from; i <= to; i += step) result.push(i);
    return result;
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range in segment: "${segment}"`);
    }
    if (start < min || end > max || start > end) {
      throw new Error(
        `Range "${segment}" out of bounds [${min}-${max}]`
      );
    }
    return rangeArray(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value in segment: "${segment}"`);
  }
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of bounds [${min}-${max}]`);
  }
  return [value];
}

function parseField(expression: string, field: CronField): number[] {
  const parts = expression.split(",");
  const values = new Set<number>();
  for (const part of parts) {
    for (const v of parseSegment(part.trim(), field)) {
      values.add(v);
    }
  }
  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const result = {} as ParsedCron;
  for (let i = 0; i < FIELD_NAMES.length; i++) {
    const name = FIELD_NAMES[i];
    result[name] = parseField(fields[i], FIELD_RANGES[name]);
  }
  return result;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldConfig = { min: number; max: number };

const FIELD_CONFIGS: Record<keyof CronFields, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in field: ${context}`);
  }
}

function parseField(expr: string, config: FieldConfig, fieldName: string): number[] {
  const { min, max } = config;
  const results = new Set<number>();

  const parts = expr.split(",");

  for (const part of parts) {
    if (part === "*") {
      for (let i = min; i <= max; i++) results.add(i);
      continue;
    }

    const stepMatch = part.match(/^(\*|(\d+)-(\d+)|\d+)\/(\d+)$/);
    if (stepMatch) {
      const stepSize = parseInt(stepMatch[4], 10);
      if (stepSize <= 0) throw new RangeError(`Step must be > 0 in field: ${fieldName}`);

      let rangeMin: number;
      let rangeMax: number;

      if (stepMatch[1] === "*") {
        rangeMin = min;
        rangeMax = max;
      } else if (stepMatch[2] !== undefined) {
        rangeMin = parseInt(stepMatch[2], 10);
        rangeMax = parseInt(stepMatch[3], 10);
        assertInRange(rangeMin, min, max, fieldName);
        assertInRange(rangeMax, min, max, fieldName);
        if (rangeMin > rangeMax) throw new RangeError(`Range start > end in field: ${fieldName}`);
      } else {
        rangeMin = parseInt(stepMatch[1], 10);
        assertInRange(rangeMin, min, max, fieldName);
        rangeMax = max;
      }

      for (let i = rangeMin; i <= rangeMax; i += stepSize) results.add(i);
      continue;
    }

    const rangeMatch = part.match(/^(\d+)-(\d+)$/);
    if (rangeMatch) {
      const start = parseInt(rangeMatch[1], 10);
      const end = parseInt(rangeMatch[2], 10);
      assertInRange(start, min, max, fieldName);
      assertInRange(end, min, max, fieldName);
      if (start > end) throw new RangeError(`Range start > end in field: ${fieldName}`);
      for (let i = start; i <= end; i++) results.add(i);
      continue;
    }

    const numMatch = part.match(/^(\d+)$/);
    if (numMatch) {
      const value = parseInt(numMatch[1], 10);
      assertInRange(value, min, max, fieldName);
      results.add(value);
      continue;
    }

    throw new SyntaxError(`Invalid cron field expression "${part}" in field: ${fieldName}`);
  }

  return Array.from(results).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(`Expected 5 cron fields, got ${fields.length}`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;
  const fieldNames = Object.keys(FIELD_CONFIGS) as (keyof CronFields)[];
  const exprs = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  return fieldNames.reduce((acc, fieldName, i) => {
    acc[fieldName] = parseField(exprs[i], FIELD_CONFIGS[fieldName], fieldName);
    return acc;
  }, {} as CronFields);
}

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronExpression, [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
};

function rangeArray(from: number, to: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = from; i <= to; i += step) result.push(i);
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  // Comma-separated list
  if (field.includes(",")) {
    return field
      .split(",")
      .flatMap((part) => parseField(part.trim(), min, max))
      .filter((v, i, a) => a.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  // Wildcard
  if (field === "*") return rangeArray(min, max);

  // Step value: */n or start-end/n
  if (field.includes("/")) {
    const [rangePart, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step value: "${field}"`);

    let from = min;
    let to = max;
    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        [from, to] = rangePart.split("-").map(Number);
      } else {
        from = parseInt(rangePart, 10);
      }
    }
    return rangeArray(from, to, step).filter((v) => v >= min && v <= max);
  }

  // Range: start-end
  if (field.includes("-")) {
    const [fromStr, toStr] = field.split("-");
    const from = parseInt(fromStr, 10);
    const to = parseInt(toStr, 10);
    if (isNaN(from) || isNaN(to) || from > to)
      throw new Error(`Invalid range: "${field}"`);
    if (from < min || to > max)
      throw new Error(`Range "${field}" out of bounds [${min}, ${max}]`);
    return rangeArray(from, to);
  }

  // Single number
  const value = parseInt(field, 10);
  if (isNaN(value)) throw new Error(`Invalid cron field value: "${field}"`);
  if (value < min || value > max)
    throw new Error(`Value ${value} out of bounds [${min}, ${max}]`);
  return [value];
}

export default function parseCron(expression: string): CronExpression {
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5)
    throw new Error(`Expected 5 fields, got ${parts.length}: "${expression}"`);

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronExpression)[];

  return fieldNames.reduce((acc, name, i) => {
    const [min, max] = FIELD_RANGES[name];
    acc[name] = parseField(parts[i], min, max);
    return acc;
  }, {} as CronExpression);
}

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: [keyof CronExpression, FieldConfig][] = [
  ["minute", { min: 0, max: 59 }],
  ["hour", { min: 0, max: 23 }],
  ["dayOfMonth", { min: 1, max: 31 }],
  ["month", { min: 1, max: 12 }],
  ["dayOfWeek", { min: 0, max: 6 }],
];

function range(start: number, end: number): number[] {
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
  }
}

function parseSegment(segment: string, { min, max }: FieldConfig, fieldName: string): number[] {
  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Step value: */n or start-end/n
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value "${stepPart}" in field "${fieldName}"`);
    }
    const [start, end] =
      rangePart === "*"
        ? [min, max]
        : rangePart.split("-").map((v) => {
            const n = parseInt(v, 10);
            if (isNaN(n)) throw new SyntaxError(`Invalid range value "${v}" in field "${fieldName}"`);
            return n;
          });
    assertInRange(start, min, max, fieldName);
    assertInRange(end, min, max, fieldName);
    if (start > end) throw new RangeError(`Range start ${start} > end ${end} in field "${fieldName}"`);
    return range(start, end).filter((v) => (v - start) % step === 0);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${fieldName}"`);
    }
    const start = parseInt(parts[0], 10);
    const end = parseInt(parts[1], 10);
    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range values in "${segment}" in field "${fieldName}"`);
    }
    assertInRange(start, min, max, fieldName);
    assertInRange(end, min, max, fieldName);
    if (start > end) throw new RangeError(`Range start ${start} > end ${end} in field "${fieldName}"`);
    return range(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}" in field "${fieldName}"`);
  }
  assertInRange(value, min, max, fieldName);
  return [value];
}

function parseField(expression: string, config: FieldConfig, fieldName: string): number[] {
  const segments = expression.split(",");
  const values = new Set<number>();
  for (const segment of segments) {
    for (const v of parseSegment(segment.trim(), config, fieldName)) {
      values.add(v);
    }
  }
  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(`Expected 5 fields, got ${fields.length}`);
  }

  const result = {} as CronExpression;
  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const [name, config] = FIELD_CONFIGS[i];
    result[name] = parseField(fields[i], config, name);
  }
  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronFields, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: (keyof CronFields)[] = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
];

function range(from: number, to: number, step = 1): number[] {
  if (step < 1) throw new Error(`Step must be >= 1, got ${step}`);
  const result: number[] = [];
  for (let i = from; i <= to; i += step) result.push(i);
  return result;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Wildcard with optional step: * or */N
  if (segment.startsWith("*")) {
    if (segment === "*") return range(min, max);
    const stepStr = segment.slice(2);
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step: "${stepStr}"`);
    return range(min, max, step);
  }

  // Range with optional step: N-M or N-M/S
  if (segment.includes("-")) {
    const [rangePart, stepPart] = segment.split("/");
    const [startStr, endStr] = rangePart.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    const step = stepPart !== undefined ? parseInt(stepPart, 10) : 1;

    if (isNaN(start) || isNaN(end) || isNaN(step)) {
      throw new Error(`Invalid range segment: "${segment}"`);
    }
    if (start < min || end > max || start > end) {
      throw new Error(
        `Range ${start}-${end} out of bounds [${min}-${max}]: "${segment}"`
      );
    }
    if (step < 1) throw new Error(`Step must be >= 1: "${segment}"`);
    return range(start, end, step);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid value: "${segment}"`);
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of bounds [${min}-${max}]`);
  }
  return [value];
}

function parseField(expression: string, config: FieldConfig): number[] {
  const parts = expression.split(",");
  const values = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (!trimmed) throw new Error(`Empty field segment in: "${expression}"`);
    for (const v of parseSegment(trimmed, config)) values.add(v);
  }

  return [...values].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;
  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name = FIELD_ORDER[i];
    result[name] = parseField(fields[i], FIELD_CONFIGS[name]);
  }

  return result;
}
